    int eval_rc = ds4_session_eval(session, token, err, sizeof(err));
    cli_dist_busy_set(cfg, false);
    if (eval_rc != 0) {
        fprintf(stderr, "ds4: decode failed: %s\n", err);
        ds4_session_free(session);
        return 1;
    }
    toks[0] = token;
    ntok = 1;
}

